"use client";

import { useCallback, useRef } from "react";

/**
 * Trigger a `lucide-animated` icon's animation from a **parent**
 * element rather than the icon itself.
 *
 * `lucide-animated` icons listen to their own `mouseenter` /
 * `mouseleave` by default — so visitors hovering a button never see
 * the icon animate (they're hovering the button, not the SVG). This
 * hook returns:
 *
 *   - `iconRef` — pass to the icon via `<MicIcon ref={iconRef} />`
 *   - `parentHandlers` — spread onto the parent (button / pill /
 *     row) you want to drive the hover from
 *
 * The icon's handle type carries `startAnimation` / `stopAnimation`
 * methods; we call them defensively (the spread `?.` short-circuits
 * if the icon's ref shape ever changes upstream).
 *
 * Usage:
 *     const { iconRef, parentHandlers } = useIconHover<MicIconHandle>();
 *     <button {...parentHandlers}>
 *       <MicIcon ref={iconRef} />
 *     </button>
 */
export function useIconHover<
  Handle extends {
    startAnimation?: () => void;
    stopAnimation?: () => void;
  },
>(): {
  iconRef: React.MutableRefObject<Handle | null>;
  parentHandlers: {
    onMouseEnter: () => void;
    onMouseLeave: () => void;
    onFocus: () => void;
    onBlur: () => void;
  };
} {
  const iconRef = useRef<Handle | null>(null);

  const start = useCallback(() => {
    iconRef.current?.startAnimation?.();
  }, []);
  const stop = useCallback(() => {
    iconRef.current?.stopAnimation?.();
  }, []);

  return {
    iconRef,
    parentHandlers: {
      onMouseEnter: start,
      onMouseLeave: stop,
      // Keyboard parity — when a button gets focus via Tab, the
      // icon should animate too, matching mouse-hover behaviour.
      onFocus: start,
      onBlur: stop,
    },
  };
}
